export interface SuperiTransport {
request<M extends keyof SuperiMethodMap>(
method: M,
request: SuperiMethodMap[M]["request"],
): Promise<SuperiMethodMap[M]["response"]>;
subscribe?<E extends keyof SuperiEventMap>(
event: E,
listener: (payload: SuperiEventMap[E]) => void,
): () => void;
}

export class SuperiTransportError extends Error {
public readonly publicError: PublicApiError;

public constructor(publicError: PublicApiError) {
super(publicError.message);
this.name = "SuperiTransportError";
this.publicError = publicError;
}
}

export class SuperiClient {
public constructor(private readonly transport: SuperiTransport) {}

public request<M extends keyof SuperiMethodMap>(
method: M,
request: SuperiMethodMap[M]["request"],
): Promise<SuperiMethodMap[M]["response"]> {
return this.transport.request(method, request);
}

public subscribe<E extends keyof SuperiEventMap>(
event: E,
listener: (payload: SuperiEventMap[E]) => void,
): () => void {
if (!this.transport.subscribe) {
throw new Error("the configured Superi transport does not support subscriptions");
}
return this.transport.subscribe(event, listener);
}
}

export type JsonRpcId = string;

export interface SuperiJsonRpcRequest<M extends keyof SuperiMethodMap> {
jsonrpc: "2.0";
id: JsonRpcId;
method: M;
params: SuperiMethodMap[M]["request"];
}

export interface SuperiJsonRpcSuccess<M extends keyof SuperiMethodMap> {
jsonrpc: "2.0";
id: JsonRpcId;
result: SuperiMethodMap[M]["response"];
}

export interface SuperiJsonRpcFailure {
jsonrpc: "2.0";
id: JsonRpcId;
error: PublicApiError;
}

export type SuperiJsonRpcResponse<M extends keyof SuperiMethodMap> =
| SuperiJsonRpcSuccess<M>
| SuperiJsonRpcFailure;
